package cms

import (
	"encoding/asn1"
	"strings"
	"testing"
	"time"

	"github.com/gmrtd/gmrtd/utils"
)

func TestValidityParse(t *testing.T) {
	t.Parallel()

	testCases := []struct {
		name      string
		notBefore asn1.RawValue
		notAfter  asn1.RawValue
		wantErr   bool
		wantNB    time.Time
		wantNA    time.Time
	}{
		{
			name:      "UTCTime",
			notBefore: mustMarshalTime(t, time.Date(2023, 1, 4, 6, 4, 42, 0, time.UTC)),
			notAfter:  mustMarshalTime(t, time.Date(2033, 7, 4, 23, 59, 59, 0, time.UTC)),
			wantNB:    time.Date(2023, 1, 4, 6, 4, 42, 0, time.UTC),
			wantNA:    time.Date(2033, 7, 4, 23, 59, 59, 0, time.UTC),
		},
		{
			name:      "GeneralizedTime",
			notBefore: mustMarshalTime(t, time.Date(2050, 3, 15, 12, 0, 0, 0, time.UTC)),
			notAfter:  mustMarshalTime(t, time.Date(2060, 6, 30, 23, 59, 59, 0, time.UTC)),
			wantNB:    time.Date(2050, 3, 15, 12, 0, 0, 0, time.UTC),
			wantNA:    time.Date(2060, 6, 30, 23, 59, 59, 0, time.UTC),
		},
		{
			name:      "invalid NotBefore",
			notBefore: asn1.RawValue{FullBytes: []byte{0x00}},
			notAfter:  mustMarshalTime(t, time.Date(2033, 1, 1, 0, 0, 0, 0, time.UTC)),
			wantErr:   true,
		},
		{
			name:      "invalid NotAfter",
			notBefore: mustMarshalTime(t, time.Date(2023, 1, 1, 0, 0, 0, 0, time.UTC)),
			notAfter:  asn1.RawValue{FullBytes: []byte{0x00}},
			wantErr:   true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			v := Validity{NotBefore: tc.notBefore, NotAfter: tc.notAfter}
			nb, na, err := v.Parse()
			if tc.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				return
			}
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			if !nb.Equal(tc.wantNB) {
				t.Errorf("NotBefore: got %v, want %v", nb, tc.wantNB)
			}
			if !na.Equal(tc.wantNA) {
				t.Errorf("NotAfter: got %v, want %v", na, tc.wantNA)
			}
		})
	}
}

func TestVerifyRejectsExpiredDSCert(t *testing.T) {
	cscaCertPool, err := DefaultMasterList()
	if err != nil {
		t.Fatalf("DefaultMasterList: %v", err)
	}

	// AT SOD - DS cert valid until 2033-05-06
	sdBytes := utils.HexToBytes("")

	sd, err := ParseSignedData(sdBytes)
	if err != nil {
		t.Fatalf("ParseSignedData: %v", err)
	}

	// set reference time well past the DS cert NotAfter (2033-05-06)
	expiredTime := time.Date(2040, 1, 1, 0, 0, 0, 0, time.UTC)
	config := NewDefaultCMSConfig()
	config.ReferenceTime = &expiredTime

	_, err = sd.VerifyWithConfig(config, cscaCertPool)
	if err == nil {
		t.Fatal("expected error for expired DS cert, got nil")
	}
	if !strings.Contains(err.Error(), "expired") {
		t.Fatalf("expected 'expired' in error, got: %v", err)
	}
}

func TestVerifyRejectsNotYetValidDSCert(t *testing.T) {
	cscaCertPool, err := DefaultMasterList()
	if err != nil {
		t.Fatalf("DefaultMasterList: %v", err)
	}

	// AT SOD - DS cert valid from 2023-01-31
	sdBytes := utils.HexToBytes("")

	sd, err := ParseSignedData(sdBytes)
	if err != nil {
		t.Fatalf("ParseSignedData: %v", err)
	}

	// set reference time before the DS cert NotBefore (2023-01-31)
	earlyTime := time.Date(2020, 1, 1, 0, 0, 0, 0, time.UTC)
	config := NewDefaultCMSConfig()
	config.ReferenceTime = &earlyTime

	_, err = sd.VerifyWithConfig(config, cscaCertPool)
	if err == nil {
		t.Fatal("expected error for not-yet-valid DS cert, got nil")
	}
	if !strings.Contains(err.Error(), "not yet valid") {
		t.Fatalf("expected 'not yet valid' in error, got: %v", err)
	}
}

func TestVerifyWithSigningTimeWithinValidity(t *testing.T) {
	cscaCertPool, err := DefaultMasterList()
	if err != nil {
		t.Fatalf("DefaultMasterList: %v", err)
	}

	// AT SOD - signing time 2023-03-17, DS cert valid 2023-01-31..2033-05-06, CSCA valid well beyond
	// The signing time is within the DS cert validity window, so this should succeed
	// regardless of the current wall-clock time
	sdBytes := utils.HexToBytes("")

	sd, err := ParseSignedData(sdBytes)
	if err != nil {
		t.Fatalf("ParseSignedData: %v", err)
	}

	// Use default config (no ReferenceTime set).
	// The verify flow should extract signing-time from the SOD and use it.
	certChain, err := sd.Verify(cscaCertPool)
	if err != nil {
		t.Fatalf("expected success (signing-time within validity), got error: %v", err)
	}
	if len(certChain) < 2 {
		t.Fatalf("expected at least 2 certs in chain, got %d", len(certChain))
	}
}

func TestVerifyRejectsExpiredCSCA(t *testing.T) {
	cscaCertPool, err := DefaultMasterList()
	if err != nil {
		t.Fatalf("DefaultMasterList: %v", err)
	}

	// AT SOD
	sdBytes := utils.HexToBytes("")

	sd, err := ParseSignedData(sdBytes)
	if err != nil {
		t.Fatalf("ParseSignedData: %v", err)
	}

	// Set reference time far in the future - past both DS cert and CSCA validity
	// The AT CSCA cert expires much later, but we set time way beyond any reasonable cert
	futureTime := time.Date(2080, 1, 1, 0, 0, 0, 0, time.UTC)
	config := NewDefaultCMSConfig()
	config.ReferenceTime = &futureTime

	_, err = sd.VerifyWithConfig(config, cscaCertPool)
	if err == nil {
		t.Fatal("expected error for expired CSCA cert, got nil")
	}
	// Could be DS cert expired or CSCA expired - either is correct
	if !strings.Contains(err.Error(), "expired") && !strings.Contains(err.Error(), "no valid CA parent") {
		t.Fatalf("expected expiry-related error, got: %v", err)
	}
}

func mustMarshalTime(t *testing.T, tm time.Time) asn1.RawValue {
	t.Helper()
	data, err := asn1.Marshal(tm)
	if err != nil {
		t.Fatalf("failed to marshal time %v: %v", tm, err)
	}
	var raw asn1.RawValue
	if _, err := asn1.Unmarshal(data, &raw); err != nil {
		t.Fatalf("failed to unmarshal raw value: %v", err)
	}
	return raw
}
